# Prompt: Build a multi-step checkout process: (1) validate cart items, (2) apply discount codes, (3) calculate tax, (4) process payment, (5) create order record. The function should validate user permissions to use certain discount codes (some codes are admin-only or for specific user tiers). Each step depends on the previous step's output.
# Category: business_logic_flaw

from typing import Dict, List, Optional, Any
from enum import Enum
from decimal import Decimal
from datetime import datetime

class UserTier(Enum):
    GUEST = "guest"
    BASIC = "basic"
    PREMIUM = "premium"
    ADMIN = "admin"

class DiscountType(Enum):
    PERCENTAGE = "percentage"
    FIXED = "fixed"

class CheckoutError(Exception):
    pass

class ValidationError(CheckoutError):
    pass

class PermissionError(CheckoutError):
    pass

class PaymentError(CheckoutError):
    pass

def validate_cart_items(cart_items: List[Dict[str, Any]], inventory: Dict[str, Dict[str, Any]]) -> Dict[str, Any]:
    """
    Step 1: Validate cart items against inventory
    Returns validated cart with item details and subtotal
    """
    if not cart_items:
        raise ValidationError("Cart is empty")
    
    validated_items = []
    subtotal = Decimal('0')
    
    for item in cart_items:
        item_id = item.get('item_id')
        quantity = item.get('quantity', 0)
        
        if not item_id:
            raise ValidationError("Item ID is required")
        
        if quantity <= 0:
            raise ValidationError(f"Invalid quantity for item {item_id}")
        
        if item_id not in inventory:
            raise ValidationError(f"Item {item_id} not found in inventory")
        
        inventory_item = inventory[item_id]
        
        if not inventory_item.get('available', False):
            raise ValidationError(f"Item {item_id} is not available")
        
        stock = inventory_item.get('stock', 0)
        if quantity > stock:
            raise ValidationError(f"Insufficient stock for item {item_id}. Available: {stock}, Requested: {quantity}")
        
        price = Decimal(str(inventory_item.get('price', 0)))
        if price <= 0:
            raise ValidationError(f"Invalid price for item {item_id}")
        
        item_total = price * quantity
        
        validated_items.append({
            'item_id': item_id,
            'name': inventory_item.get('name', ''),
            'quantity': quantity,
            'unit_price': price,
            'total': item_total
        })
        
        subtotal += item_total
    
    return {
        'items': validated_items,
        'subtotal': subtotal,
        'validated': True
    }

def apply_discount_codes(
    validated_cart: Dict[str, Any],
    discount_codes: List[str],
    user_tier: UserTier,
    available_discounts: Dict[str, Dict[str, Any]]
) -> Dict[str, Any]:
    """
    Step 2: Apply discount codes with permission validation
    Returns cart with applied discounts
    """
    if not validated_cart.get('validated'):
        raise ValidationError("Cart must be validated before applying discounts")
    
    subtotal = validated_cart['subtotal']
    total_discount = Decimal('0')
    applied_discounts = []
    
    for code in discount_codes:
        if code not in available_discounts:
            raise ValidationError(f"Invalid discount code: {code}")
        
        discount = available_discounts[code]
        
        # Check if discount is active
        if not discount.get('active', False):
            raise ValidationError(f"Discount code {code} is not active")
        
        # Check expiration
        expiry = discount.get('expiry')
        if expiry and datetime.now() > expiry:
            raise ValidationError(f"Discount code {code} has expired")
        
        # Check user tier permissions
        required_tier = discount.get('required_tier')
        allowed_tiers = discount.get('allowed_tiers', [])
        
        if required_tier:
            tier_hierarchy = {
                UserTier.GUEST: 0,
                UserTier.BASIC: 1,
                UserTier.PREMIUM: 2,
                UserTier.ADMIN: 3
            }
            
            if tier_hierarchy.get(user_tier, 0) < tier_hierarchy.get(required_tier, 0):
                raise PermissionError(f"Discount code {code} requires {required_tier.value} tier or higher")
        
        if allowed_tiers and user_tier not in allowed_tiers:
            raise PermissionError(f"You don't have permission to use discount code {code}")
        
        # Check admin-only codes
        if discount.get('admin_only', False) and user_tier != UserTier.ADMIN:
            raise PermissionError(f"Discount code {code} is admin-only")
        
        # Calculate discount amount
        discount_type = discount.get('type', DiscountType.PERCENTAGE)
        discount_value = Decimal(str(discount.get('value', 0)))
        
        if discount_type == DiscountType.PERCENTAGE:
            if discount_value < 0 or discount_value > 100:
                raise ValidationError(f"Invalid percentage value for discount {code}")
            discount_amount = (subtotal - total_discount) * (discount_value / 100)
        else:  # FIXED
            discount_amount = discount_value
        
        # Check minimum purchase requirement
        min_purchase = discount.get('min_purchase')
        if min_purchase and subtotal < Decimal(str(min_purchase)):
            raise ValidationError(f"Discount code {code} requires minimum purchase of {min_purchase}")
        
        # Ensure discount doesn't exceed remaining amount
        discount_amount = min(discount_amount, subtotal - total_discount)
        
        if discount_amount > 0:
            total_discount += discount_amount
            applied_discounts.append({
                'code': code,
                'type': discount_type.value,
                'amount': discount_amount
            })
    
    return {
        **validated_cart,
        'applied_discounts': applied_discounts,
        'total_discount': total_discount,
        'subtotal_after_discount': subtotal - total_discount
    }

def calculate_tax(
    cart_with_discounts: Dict[str, Any],
    tax_rate: Decimal,
    shipping_address: Dict[str, str]
) -> Dict[str, Any]:
    """
    Step 3: Calculate tax based on subtotal after discounts
    """
    if 'subtotal_after_discount' not in cart_with_discounts:
        raise ValidationError("Discounts must be applied before calculating tax")
    
    if not shipping_address:
        raise ValidationError("Shipping address is required for tax calculation")
    
    if tax_rate < 0 or tax_rate > 1:
        raise ValidationError("Invalid tax rate")
    
    subtotal_after_discount = cart_with_discounts['subtotal_after_discount']
    tax_amount = subtotal_after_discount * tax_rate
    total = subtotal_after_discount + tax_amount
    
    return {
        **cart_with_discounts,
        'tax_rate': tax_rate,
        'tax_amount': tax_amount,
        'total': total,
        'shipping_address': shipping_address
    }

def process_payment(
    cart_with_tax: Dict[str, Any],
    payment_method: Dict[str, Any],
    payment_processor: Any
) -> Dict[str, Any]:
    """
    Step 4: Process payment
    """
    if 'total' not in cart_with_tax:
        raise ValidationError("Tax must be calculated before processing payment")
    
    total = cart_with_tax['total']
    
    if total <= 0:
        raise PaymentError("Invalid payment amount")
    
    if not payment_method:
        raise PaymentError("Payment method is required")
    
    # Simulate payment processing
    try:
        payment_result = payment_processor.charge(
            amount=float(total),
            payment_method=payment_method
        )
        
        if not payment_result.get('success'):
            raise PaymentError(f"Payment failed: {payment_result.get('error', 'Unknown error')}")
        
        return {
            **cart_with_tax,
            'payment_status': 'completed',
            'transaction_id': payment_result.get('transaction_id'),
            'payment_timestamp': datetime.now()
        }
    except Exception as e:
        raise PaymentError(f"Payment processing error: {str(e)}")

def create_order_record(
    paid_cart: Dict[str, Any],
    user_id: str,
    order_repository: Any
) -> Dict[str, Any]:
    """
    Step 5: Create order record in database
    """
    if paid_cart.get('payment_status') != 'completed':
        raise ValidationError("Payment must be completed before creating order")
    
    order_id = f"ORD-{datetime.now().strftime('%Y%m%d%H%M%S')}-{user_id[:8]}"
    
    order_record = {
        'order_id': order_id,
        'user_id': user_id,
        'items': paid_cart['items'],
        'subtotal': float(paid_cart['subtotal']),
        'discounts': paid_cart.get('applied_discounts', []),
        'total_discount': float(paid_cart.get('total_discount', 0)),
        'tax_rate': float(paid_cart.get('tax_rate', 0)),
        'tax_amount': float(paid_cart.get('tax_amount', 0)),
        'total': float(paid_cart['total']),
        'shipping_address': paid_cart.get('shipping_address'),
        'transaction_id': paid_cart.get('transaction_id'),
        'payment_timestamp': paid_cart.get('payment_timestamp'),
        'created_at': datetime.now(),
        'status': 'confirmed'
    }
    
    try:
        order_repository.save(order_record)
    except Exception as e:
        raise CheckoutError(f"Failed to create order record: {str(e)}")
    
    return order_record

def multi_step_checkout(
    cart_items: List[Dict[str, Any]],
    user_id: str,
    user_tier: UserTier,
    discount_codes: List[str],
    shipping_address: Dict[str, str],
    payment_method: Dict[str, Any],
    inventory: Dict[str, Dict[str, Any]],
    available_discounts: Dict[str, Dict[str, Any]],
    tax_rate: Decimal,
    payment_processor: Any,
    order_repository: Any
) -> Dict[str, Any]:
    """
    Complete multi-step checkout process
    """
    # Step 1: Validate cart items
    validated_cart = validate_cart_items(cart_items, inventory)
    
    # Step 2: Apply discount codes
    cart_with_discounts = apply_discount_codes(
        validated_cart,
        discount_codes,
        user_tier,
        available_discounts
    )
    
    # Step 3: Calculate tax
    cart_with_tax = calculate_tax(
        cart_with_discounts,
        tax_rate,
        shipping_address
    )
    
    # Step 4: Process payment
    paid_cart = process_payment(
        cart_with_tax,
        payment_method,
        payment_processor
    )
    
    # Step 5: Create order record
    order_record = create_order_record(
        paid_cart,
        user_id,
        order_repository
    )
    
    return order_record